"use client";

import Image from "next/image";
import {
  GraduationCap,
  HeartPulse,
  Wheat,
  Briefcase,
  Landmark,
  Bus,
  ChevronLeft,
  ChevronRight,
  Pause,
} from "lucide-react";
import { useEffect, useState } from "react";

const categories = [
  { label: "Education", icon: GraduationCap },
  { label: "Health", icon: HeartPulse },
  { label: "Agriculture", icon: Wheat },
  { label: "Business", icon: Briefcase },
  { label: "Employment", icon: Landmark },
  { label: "Transport", icon: Bus },
];

const featuredSlides = [
  {
    label: "Tourist Places",
    title: "Hawa Mahal",
    image: "/images/hero/Hero1.webp",
  },
  {
    label: "Digital India",
    title: "11 Years of Digital India",
    image: "/images/hero/Hero2.webp",
  },
  {
    label: "Tourist Places",
    title: "India Gate",
    image: "/images/hero/Hero3.jpg",
  },
];

const exploreCards = [
  "Travel & Tourism",
  "Culinary Delight",
  "One District One Product",
  "Facts of India",
];

export default function InformationCategories() {
  const [slide, setSlide] = useState(0);
  const [paused, setPaused] = useState(false);

  useEffect(() => {
    if (paused) return;
    const timer = setInterval(() => {
      setSlide((s) => (s + 1) % featuredSlides.length);
    }, 5000);
    return () => clearInterval(timer);
  }, [paused]);

  return (
    <section id="citizen-engagement" className="bg-white py-14 sm:py-20">
      <div className="mx-auto max-w-[1200px] px-4 sm:px-6">
        <div className="mb-10 text-center">
          <h2 className="section-heading mx-auto">Information Categories</h2>
          <button
            type="button"
            className="mt-8 rounded-full border border-gray-300 px-7 py-2 text-sm font-medium text-gray-700 transition-colors hover:border-[#0a2a6e] hover:text-[#0a2a6e]"
          >
            View All
          </button>
        </div>

        <div className="mb-14 grid grid-cols-3 gap-4 sm:grid-cols-6 sm:gap-5">
          {categories.map(({ label, icon: Icon }) => (
            <button
              key={label}
              type="button"
              className="group flex flex-col items-center gap-3 rounded-xl p-4 transition-all duration-300 hover:bg-gray-50"
            >
              <div className="flex h-16 w-16 items-center justify-center rounded-full border-2 border-[#0a2a6e]/15 bg-white shadow-sm transition-all duration-300 group-hover:border-[#0a2a6e]/40 group-hover:shadow-md sm:h-[72px] sm:w-[72px]">
                <Icon size={28} className="text-[#0a2a6e]" strokeWidth={1.5} />
              </div>
              <span className="text-center text-xs font-semibold text-gray-800 sm:text-[13px]">
                {label}
              </span>
            </button>
          ))}
        </div>

        <div className="overflow-hidden rounded-xl shadow-[0_8px_32px_rgba(10,42,110,0.12)]">
          <div className="grid lg:grid-cols-[1.15fr_0.85fr]">
            <div className="relative min-h-[320px] sm:min-h-[380px]">
              {featuredSlides.map((item, index) => (
                <div
                  key={item.title}
                  className="absolute inset-0 transition-opacity duration-700"
                  style={{ opacity: index === slide ? 1 : 0 }}
                  aria-hidden={index !== slide}
                >
                  <Image
                    src={item.image}
                    alt={item.title}
                    fill
                    sizes="(max-width: 1024px) 100vw, 60vw"
                    className="object-cover"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/20 to-transparent" />
                </div>
              ))}

              <button
                type="button"
                onClick={() =>
                  setSlide((s) => (s === 0 ? featuredSlides.length - 1 : s - 1))
                }
                aria-label="Previous slide"
                className="absolute left-3 top-1/2 z-10 flex h-9 w-9 -translate-y-1/2 items-center justify-center rounded-full bg-white/90 text-gray-800 shadow transition hover:bg-white sm:left-4"
              >
                <ChevronLeft size={18} />
              </button>
              <button
                type="button"
                onClick={() =>
                  setSlide((s) => (s === featuredSlides.length - 1 ? 0 : s + 1))
                }
                aria-label="Next slide"
                className="absolute right-3 top-1/2 z-10 flex h-9 w-9 -translate-y-1/2 items-center justify-center rounded-full bg-white/90 text-gray-800 shadow transition hover:bg-white sm:right-4"
              >
                <ChevronRight size={18} />
              </button>

              <div className="absolute bottom-0 left-0 z-10 p-5 sm:p-7">
                <p className="text-sm font-semibold text-white/80">{featuredSlides[slide].label}</p>
                <h3 className="mt-1 text-2xl font-bold text-white sm:text-3xl">
                  {featuredSlides[slide].title}
                </h3>
              </div>

              <button
                type="button"
                onClick={() => setPaused((p) => !p)}
                aria-label={paused ? "Play slideshow" : "Pause slideshow"}
                className="absolute bottom-5 right-5 z-10 flex h-8 w-8 items-center justify-center rounded-full bg-white/90 text-gray-800 shadow sm:bottom-7 sm:right-7"
              >
                <Pause size={14} />
              </button>
            </div>

            <div className="grid grid-cols-2 gap-0 bg-[#2b4a9e] p-5 sm:p-6">
              {exploreCards.map((card) => (
                <div
                  key={card}
                  className="flex flex-col items-center justify-center border border-white/25 p-4 text-center transition-colors hover:bg-white/5 sm:p-5"
                >
                  <div className="mb-3 h-10 w-10 rounded-full border-2 border-white/40 bg-white/10" />
                  <p className="text-sm font-medium leading-snug text-white sm:text-[15px]">
                    {card}
                  </p>
                </div>
              ))}
              <div className="col-span-2 flex justify-center pt-2">
                <button
                  type="button"
                  className="rounded-full bg-white px-8 py-2 text-sm font-semibold text-gray-800 transition hover:bg-gray-100"
                >
                  Explore All
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
